import sys

def is_valid(s, t):
    len_s = len(s)
    len_t = len(t)

    # Case 1: s == t
    if s == t:
        return True

    # Case 2: s is obtained by inserting one character into t
    if len_s == len_t + 1:
        i = 0
        j = 0
        diff = 0
        while i < len_s and j < len_t:
            if s[i] == t[j]:
                i += 1
                j += 1
            else:
                i += 1
                diff += 1
                if diff > 1:
                    return False
        return True

    # Case 3: s is obtained by deleting one character from t
    if len_s == len_t - 1:
        i = 0
        j = 0
        diff = 0
        while i < len_s and j < len_t:
            if s[i] == t[j]:
                i += 1
                j += 1
            else:
                j += 1
                diff += 1
                if diff > 1:
                    return False
        return True

    # Case 4: s is obtained by changing one character in t
    if len_s == len_t:
        diff = 0
        for a, b in zip(s, t):
            if a != b:
                diff += 1
                if diff > 1:
                    return False
        return True

    return False

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    T_prime = data[1]
    S_list = data[2:]

    result = []
    for idx, s in enumerate(S_list, 1):
        if is_valid(s, T_prime):
            result.append(idx)

    print(len(result))
    if result:
        print(' '.join(map(str, result)))

if __name__ == "__main__":
    main()
